        pipe_.InitBuffer(tmpQueue_, 2, (stride1Length_ > 0 ? stride1Length_ : 1u) * sizeof(float));
        pipe_.InitBuffer(outQueue_, 1, (outLength_ > 0 ? outLength_ : 1u) * sizeof(float));
    }

