                const uint64_t xOffset = static_cast<uint64_t>(line) * length_;
                AscendC::DataCopy(xPad[padding_], xGm_[xOffset], length_);
            }

            // Compute stride-1 max pooling via sliding window using k-way vmax
            AscendC::LocalTensor<float> curMax = tmpQueue_.AllocTensor<float>();
            if (stride1Length_ > 0) {
                AscendC::DataCopy(curMax, xPad, stride1Length_);
                for (uint32_t j = 1; j < kernelSize_; ++j) {
                    AscendC::LocalTensor<float> shifted = tmpQueue_.AllocTensor<float>();
                    AscendC::DataCopy(shifted, xPad[j], stride1Length_);
                    AscendC::Max(curMax, curMax, shifted, stride1Length_);
